Rule.Source:
import sailpoint.object.Custom;
  import sailpoint.object.Identity;
  import sailpoint.object.Filter;
  import sailpoint.object.Link;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.ResourceObject;
  import sailpoint.tools.Util;
  import java.util.regex.Pattern;

  Map returnMap = new HashMap();

  Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-AID");

  String dn = account.getAttribute("distinguishedName");
  String sAMAccountName = account.getAttribute("sAMAccountName");

  try{
  if (Util.isNotNullOrEmpty(dn)) {

    List ministryOUs = custom.get("ministryOUs");

    for (String ministryOU : ministryOUs) {

      if (Pattern.matches(".*." + ministryOU + ".*", dn)) {

        Map legacyMap = custom.get("legacyMap");

        String legacyNetBios = legacyMap.get(ministryOU);

        String legacyPrincipalName = legacyNetBios + "\\" + sAMAccountName;
        
        Filter filter1 = Filter.ignoreCase(Filter.eq("displayName", legacyPrincipalName));
        Filter filter2 = Filter.eq("application.type", "Active Directory - Direct");
        Filter finalFilter = Filter.and(filter1, filter2);

        Link link = context.getUniqueObject(Link.class, finalFilter);

        if (link != null) {
          
          String identityName = link.getIdentity().getName();

          returnMap.put("identityName", identityName); 
          
          return returnMap;

        }

      }

    }

  }
  }catch(Exception e){
   log.error("Exception in  Ascension-Rule-AD-AID-Correlation: "+e.getMessage());
  }
